#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define INF INT_MAX
#define MAXN 50000
#define MAXM 100000

// Define the structure for a graph edge
typedef struct {
    int u, v, w;
} Edge;

// Define the structure for a graph
typedef struct {
    int n, m;
    Edge *edges;
} Graph;

// Function to create a graph
Graph *createGraph(int n, int m) {
    Graph *g = (Graph *)malloc(sizeof(Graph));
    g->n = n;
    g->m = m;
    g->edges = (Edge *)malloc(m * sizeof(Edge));
    return g;
}

// Function to add an edge to the graph
void addEdge(Graph *g, int u, int v, int w) {
    g->edges[g->m].u = u;
    g->edges[g->m].v = v;
    g->edges[g->m].w = w;
    g->m++;
}

// Function to find the shortest distance using Dijkstra's algorithm
int dijkstra(Graph *g, int s, int t) {
    int *dist = (int *)malloc(g->n * sizeof(int));
    for (int i = 0; i < g->n; i++) {
        dist[i] = INF;
    }
    dist[s] = 0;
    for (int i = 0; i < g->n - 1; i++) {
        for (int j = 0; j < g->m; j++) {
            int u = g->edges[j].u;
            int v = g->edges[j].v;
            int w = g->edges[j].w;
            if (dist[u] != INF && dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
            }
        }
    }
    return dist[t];
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        Graph *g1 = createGraph(N, N - 1);
        Graph *g2 = createGraph(N, N - 1);
        for (int i = 0; i < N - 1; i++) {
            int u, v, w;
            scanf("%d %d %d", &u, &v, &w);
            addEdge(g1, u - 1, v - 1, w);
        }
        for (int i = 0; i < N - 1; i++) {
            int u, v, w;
            scanf("%d %d %d", &u, &v, &w);
            addEdge(g2, u - 1, v - 1, w);
        }
        long long total = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                int d1 = dijkstra(g1, i, j);
                int d2 = dijkstra(g2, i, j);
                total += (d1 <= d2) ? d1 : d2;
            }
        }
        printf("%lld\n", total);
    }
    return 0;
}

