    g.n = n;
    g.m = m;
    g.edges.resize(m);
    return g;
}

// Function to add an edge to the graph
void addEdge(Graph &g, int u, int v, int w) {
    g.edges[g.m].u = u;
    g.edges[g.m].v = v;
    g.edges[g.m].w = w;
    g.m++;
}

// Function to find the shortest distance using Dijkstra's algorithm
int dijkstra(Graph &g, int s, int t) {
    vector<int> dist(g.n, INF);
    dist[s] = 0;
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;
    pq.push({0, s});
    while (!pq.empty()) {
        int u = pq.top().second;
        pq.pop();
        for (int i = 0; i < g.m; i++) {
            int v = g.edges[i].v;
            int w = g.edges[i].w;
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                pq.push({dist[v], v});
            }
        }
    }
    return dist[t];
}

