import java.util.PriorityQueue;
import java.util.Scanner;
import java.util.Arrays;

public class Main {
    static final int INF = Integer.MAX_VALUE;
    static final int MAXN = 50000;

    // Define the structure for a graph edge
    static class Edge {
        int u, v, w;

        public Edge(int u, int v, int w) {
            this.u = u;
            this.v = v;
            this.w = w;
        }
    }

    // Define the structure for a graph
    static class Graph {
        int n, m;
        Edge[] edges;

        public Graph(int n, int m) {
            this.n = n;
            this.m = m;
            this.edges = new Edge[m];
        }
    }

    // Function to create a graph
    static Graph createGraph(int n, int m) {
        return new Graph(n, m);
    }

    // Function to add an edge to the graph
    static void addEdge(Graph g, int u, int v, int w, int index) {
        g.edges[index] = new Edge(u, v, w);
    }

    // Function to find the shortest distance using Dijkstra's algorithm
    static int dijkstra(Graph g, int s, int t) {
        int[] dist = new int[g.n];
        Arrays.fill(dist, INF);
        dist[s] = 0;
        PriorityQueue<int[]> pq = new PriorityQueue<>((a, b) -> a[0] - b[0]);
        pq.offer(new int[] {0, s});
        while (!pq.isEmpty()) {
            int[] arr = pq.poll();
            int u = arr[1];
            for (int i = 0; i < g.m; i++) {
                int v = g.edges[i].v;
                int w = g.edges[i].w;
                if (dist[u] + w < dist[v]) {
                    dist[v] = dist[u] + w;
                    pq.offer(new int[] {dist[v], v});
                }
            }
        }
        return dist[t];
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            Graph g1 = createGraph(N, N - 1);
            Graph g2 = createGraph(N, N - 1);
            for (int i = 0; i < N - 1; i++) {
                int u = sc.nextInt() - 1;
                int v = sc.nextInt() - 1;
                int w = sc.nextInt();
                addEdge(g1, u, v, w, i);
            }
            for (int i = 0; i < N - 1; i++) {
                int u = sc.nextInt() - 1;
                int v = sc.nextInt() - 1;
                int w = sc.nextInt();
                addEdge(g2, u, v, w, i);
            }
            long total = 0;
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    int d1 = dijkstra(g1, i, j);
                    int d2 = dijkstra(g2, i, j);
                    total += (d1 <= d2) ? d1 : d2;
                }
            }
            System.out.println(total);
        }
    }
}

